import{_ as i,C as n,o as r,c as s,a5 as o,b as l,w as a,a as c,E as h,a6 as p}from"./chunks/framework.JW9VOlAI.js";const k=JSON.parse('{"title":"Platform Owner","description":"","frontmatter":{},"headers":[],"relativePath":"overview/platform-owner.md","filePath":"overview/platform-owner.md"}'),d={name:"overview/platform-owner.md"};function m(u,e,g,v,w,f){const t=n("Mermaid");return r(),s("div",null,[e[1]||(e[1]=o('<h1 id="platform-owner" tabindex="-1">Platform Owner <a class="header-anchor" href="#platform-owner" aria-label="Permalink to &quot;Platform Owner&quot;">​</a></h1><p>The platform owner operates the Platform Mesh infrastructure itself -- the control plane, identity and authorization systems, and the marketplace that providers and consumers depend on. While <a href="/pr-preview/pr-80/overview/providers.html">service providers</a> define what can be ordered and <a href="/pr-preview/pr-80/overview/consumers.html">service consumers</a> use those services, the platform owner is responsible for making the ecosystem work: deploying the core components, onboarding providers, structuring the organizational hierarchy, and defining the policies that govern the entire mesh.</p><h2 id="deployment-topology" tabindex="-1">Deployment Topology <a class="header-anchor" href="#deployment-topology" aria-label="Permalink to &quot;Deployment Topology&quot;">​</a></h2><p>The platform owner deploys and operates the core Platform Mesh stack:</p><ul><li><strong>kcp</strong> -- the central control plane, providing workspaces, APIExport/APIBinding, and the virtual workspace API. For production deployments, kcp supports horizontal scaling through sharding, where multiple shards share the load of hosting workspaces.</li><li><strong>Keycloak</strong> -- OIDC-based identity management. Each organization gets its own Keycloak realm, and organizations can federate their existing identity provider.</li><li><strong>OpenFGA</strong> -- relationship-based access control, connected to kcp via its authorizer chain. Each organization gets an isolated authorization store.</li><li><strong>Platform Mesh Portal</strong> -- the reference consumer-facing portal, built on OpenMFP and Luigi. The owner configures which micro-frontend modules are available and how the portal presents the service catalog.</li><li><strong>GitOps and delivery</strong> -- Flux for continuous delivery of platform components, OCM for component packaging and versioning.</li></ul><p>The platform owner decides which components to deploy based on scale and requirements. A minimal setup might be a single kcp instance with Keycloak; a production deployment adds sharding, high availability, and the full portal stack.</p><h2 id="account-hierarchy-management" tabindex="-1">Account Hierarchy Management <a class="header-anchor" href="#account-hierarchy-management" aria-label="Permalink to &quot;Account Hierarchy Management&quot;">​</a></h2><p>The platform owner structures the <a href="/pr-preview/pr-80/concepts/account-model.html">account model</a> to mirror organizational boundaries. Each node in the hierarchy is a kcp workspace with its own API surface, identity realm, and authorization store.</p><p>Typical hierarchy patterns include:</p><ul><li><strong>Organizations</strong> at the top level, each representing a tenant or business unit</li><li><strong>Teams</strong> or <strong>projects</strong> nested within organizations</li><li><strong>Environments</strong> (development, staging, production) as leaf workspaces</li></ul><p>Policies defined at higher levels of the hierarchy propagate downward, so the platform owner can set organization-wide security baselines, resource quotas, or allowed API versions at the root and have them apply to all child workspaces automatically.</p><p>The platform owner also designates <strong>provider workspaces</strong> where service providers publish their APIExports, and <strong>marketplace workspaces</strong> where consumers discover available services.</p><h2 id="provider-onboarding" tabindex="-1">Provider Onboarding <a class="header-anchor" href="#provider-onboarding" aria-label="Permalink to &quot;Provider Onboarding&quot;">​</a></h2><p>Bringing a new service provider into the mesh is a platform owner responsibility. The workflow involves:</p><ol><li><strong>Create a provider workspace</strong> -- allocate a workspace where the provider will publish their APIExports and APIResourceSchemas.</li><li><strong>Grant credentials</strong> -- provide the service provider with a kubeconfig for their workspace, scoped to the permissions they need (managing APIExports, APIResourceSchemas, and related resources).</li><li><strong>Scope permissions</strong> -- define what the provider is allowed to export and which consumer workspaces can discover their services.</li><li><strong>Make services discoverable</strong> -- configure the marketplace so that the provider&#39;s APIExports appear in the service catalog for eligible consumers.</li></ol><p>Once onboarded, the provider follows their own <a href="/pr-preview/pr-80/overview/providers.html#provider-workflow">workflow</a> to publish APIs and fulfill orders. The platform owner monitors the health of the integration but does not need to be involved in day-to-day service operations.</p><h2 id="policy-and-governance" tabindex="-1">Policy and Governance <a class="header-anchor" href="#policy-and-governance" aria-label="Permalink to &quot;Policy and Governance&quot;">​</a></h2><p>The platform owner defines platform-wide policies that establish the rules of the ecosystem:</p><ul><li><strong>Resource quotas</strong> -- limits on how many workspaces, bindings, or resources a consumer or provider can create</li><li><strong>API version policies</strong> -- which API versions are allowed or deprecated across the platform</li><li><strong>Security baselines</strong> -- minimum authentication requirements, session policies, and access control defaults</li><li><strong>Audit and compliance</strong> -- logging and monitoring configurations that apply across the workspace hierarchy</li></ul><p>These policies are expressed as Kubernetes resources in the hierarchy and propagate through the workspace tree. Child workspaces can tighten policies but cannot relax constraints set by their parent.</p><h2 id="identity-and-authorization" tabindex="-1">Identity and Authorization <a class="header-anchor" href="#identity-and-authorization" aria-label="Permalink to &quot;Identity and Authorization&quot;">​</a></h2><p>The platform owner configures the identity and authorization infrastructure that secures all interactions in the mesh.</p><p><strong>Identity (Keycloak):</strong> Each organization gets its own Keycloak realm. The platform owner configures realm settings, enables identity federation (so organizations can bring their own identity provider), and manages the OIDC integration with kcp. Authentication decisions happen at the kcp front proxy, which validates OIDC tokens before requests reach any workspace.</p><p><strong>Authorization (OpenFGA):</strong> Each organization gets an isolated OpenFGA store. The authorization schema updates dynamically as new APIBindings are activated -- when a consumer binds to a provider&#39;s service, the relationship tuples that govern access are created automatically. The platform owner defines the base authorization model and can customize how permissions propagate through the workspace hierarchy.</p><p>Together, these systems ensure that every API request in the mesh is authenticated and authorized before it reaches any workspace, provider, or consumer resource.</p>',25)),(r(),l(p,null,{default:a(()=>[h(t,{id:"mermaid-151",class:"mermaid",graph:"flowchart%20TD%0A%20%20%20%20PO%5B%22Platform%20Owner%22%5D%0A%0A%20%20%20%20subgraph%20operates%5B%22Operates%22%5D%0A%20%20%20%20%20%20%20%20KCP%5B%22kcp%20Control%20Plane%22%5D%0A%20%20%20%20%20%20%20%20KC%5B%22Keycloak%20(Identity)%22%5D%0A%20%20%20%20%20%20%20%20FGA%5B%22OpenFGA%20(Authorization)%22%5D%0A%20%20%20%20%20%20%20%20Portal%5B%22Platform%20Mesh%20Portal%22%5D%0A%20%20%20%20end%0A%0A%20%20%20%20subgraph%20manages%5B%22Manages%22%5D%0A%20%20%20%20%20%20%20%20Accounts%5B%22Account%20Hierarchy%22%5D%0A%20%20%20%20%20%20%20%20Policies%5B%22Platform%20Policies%22%5D%0A%20%20%20%20%20%20%20%20Marketplace%5B%22Service%20Marketplace%22%5D%0A%20%20%20%20end%0A%0A%20%20%20%20PO%20--%3E%20operates%0A%20%20%20%20PO%20--%3E%20manages%0A%20%20%20%20Accounts%20--%20%22provider%20workspaces%22%20--%3E%20Providers%5B%22Service%20Providers%22%5D%0A%20%20%20%20Accounts%20--%20%22consumer%20workspaces%22%20--%3E%20Consumers%5B%22Service%20Consumers%22%5D%0A%20%20%20%20Providers%20--%20%22publish%20APIs%22%20--%3E%20Marketplace%0A%20%20%20%20Consumers%20--%20%22discover%20%26%20bind%22%20--%3E%20Marketplace%0A"})]),fallback:a(()=>[...e[0]||(e[0]=[c(" Loading... ",-1)])]),_:1})),e[2]||(e[2]=o('<h2 id="what-s-next" tabindex="-1">What&#39;s Next <a class="header-anchor" href="#what-s-next" aria-label="Permalink to &quot;What&#39;s Next&quot;">​</a></h2><ul><li><a href="/pr-preview/pr-80/overview/personas.html">Personas Overview</a> -- all three personas and how they interact</li><li><a href="/pr-preview/pr-80/concepts/account-model.html">Account Model</a> -- detailed look at the workspace hierarchy</li><li><a href="/pr-preview/pr-80/concepts/control-planes.html">Control Planes</a> -- how kcp workspaces provide isolation and multi-tenancy</li><li><a href="/pr-preview/pr-80/overview/providers.html">Service Providers</a> -- how providers publish and fulfill services</li><li><a href="/pr-preview/pr-80/overview/consumers.html">Service Consumers</a> -- how consumers discover and use services</li></ul>',2))])}const A=i(d,[["render",m]]);export{k as __pageData,A as default};
